#include<bits/stdc++.h>
#define int long long
using namespace std;
struct Tree {
	int l, r, len, lft[2], rgt[2];
} tr[800010];
int n, q;
void pushup(Tree &tM, Tree &tL, Tree &tR) {
	tM.len = max(tL.rgt[0] + tR.lft[1], tL.rgt[1] + tR.lft[0]);
	tM.len = max({tM.len, tL.len, tR.len});
	int len1 = tL.r - tL.l + 1;
	int x1 = (tL.lft[0] == 0);
	if (tL.len == len1)tM.lft[x1] = len1 + tR.lft[(x1 + len1) & 1];
	else tM.lft[x1] = tL.lft[x1];
	tM.lft[x1 ^ 1] = 0;
	int len2 = tR.r - tR.l + 1;
	int x2 = (tR.rgt[0] == 0);
	if (tR.len == len2)tM.rgt[x2] = len2 + tL.rgt[(x2 + len2) & 1];
	else tM.rgt[x2] = tR.rgt[x2];
	tM.rgt[x2 ^ 1] = 0;
}
void build(int p, int l, int r) {
	tr[p].l = l, tr[p].r = r;
	if (l == r) {
		tr[p].len = tr[p].lft[0] = tr[p].rgt[0] = 1;
		return ;
	}
	int mid = (l + r) >> 1;
	build(p << 1, l, mid);
	build(p << 1 | 1, mid + 1, r);
	pushup(tr[p], tr[p << 1], tr[p << 1 | 1]);
}
void modify(int p, int a) {
	if (tr[p].l > a || tr[p].r < a)return ;
	if (tr[p].l == tr[p].r) {
		tr[p].lft[0] ^= 1, tr[p].rgt[0] ^= 1;
		tr[p].lft[1] ^= 1, tr[p].rgt[1] ^= 1;
		return;
	}
	modify(p << 1, a);
	modify(p << 1 | 1, a);
	pushup(tr[p], tr[p << 1], tr[p << 1 | 1]);
}
signed main() {
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	cin >> n >> q;
	build(1, 1, n);
	while (q--) {
		int x;
		cin >> x;
		modify(1, x);
		cout << tr[1].len << endl;
	}
	return 0;
}
